css:
.ecf-invoice { color: #1f2937; font-size: 12px; }
.ecf-header { align-items: flex-start; border-bottom: 2px solid #111827; display: flex; justify-content: space-between; margin-bottom: 18px; padding-bottom: 12px; }
.ecf-header h1 { font-size: 22px; margin: 0 0 4px; }
.ecf-header h2 { font-size: 14px; font-weight: 600; margin: 10px 0 0; }
.ecf-invoice-meta { line-height: 1.7; text-align: right; }
.ecf-party { background: #f3f4f6; border-radius: 6px; line-height: 1.5; margin-bottom: 18px; padding: 10px 12px; }
.ecf-address { margin-top: 4px; }
.ecf-items { border-collapse: collapse; width: 100%; }
.ecf-items th { background: #111827; color: #fff; font-weight: 600; padding: 8px; text-align: left; }
.ecf-items td { border-bottom: 1px solid #e5e7eb; padding: 8px; vertical-align: top; }
.ecf-items .num { text-align: right; }
.ecf-totals { line-height: 1.8; margin-left: auto; margin-top: 14px; text-align: right; width: 45%; }
.ecf-totals div { display: flex; justify-content: space-between; }
.ecf-totals .grand-total { border-top: 2px solid #111827; font-size: 14px; margin-top: 5px; padding-top: 5px; }
.ecf-fiscal { align-items: center; border: 1px solid #9ca3af; border-radius: 8px; display: flex; justify-content: space-between; margin-top: 24px; padding: 14px; page-break-inside: avoid; }
.ecf-fiscal h3 { font-size: 14px; margin: 0 0 8px; }
.ecf-fiscal-data { line-height: 1.6; padding-right: 16px; }
.ecf-qr img { display: block; height: 145px; width: 145px; }
.ecf-warning { background: #fff7ed; border: 1px solid #fb923c; border-radius: 6px; margin-top: 24px; padding: 10px; }
.muted { color: #6b7280; font-size: 10px; }
@media print { .ecf-fiscal { break-inside: avoid; } }
